from dataclasses import dataclass, field
from datetime import datetime, timezone
import uuid

@dataclass
class ToolCallRecord:
    tool: str
    input_summary: str     # first 100 chars of the input JSON
    result_summary: str    # first 100 chars of the result JSON

@dataclass
class Episode:
    goal: str
    outcome: str           # "success" | "failed" | "partial"
    answer: str | None
    tool_calls: list[ToolCallRecord]
    iterations_used: int
    total_input_tokens: int
    tags: list[str] = field(default_factory=list)
    episode_id: str = field(default_factory=lambda: str(uuid.uuid4()))
    timestamp: str = field(default_factory=lambda: datetime.now(timezone.utc).isoformat())

    def to_context_block(self) -> str:
        """Serialise this episode as a compact context block for injection."""
        lines = [
            f"[Past episode | {self.timestamp[:10]} | {self.outcome}]",
            f"Goal: {self.goal}",
        ]
        if self.tool_calls:
            lines.append("Steps taken:")
            for tc in self.tool_calls:
                lines.append(f"  - {tc.tool}({tc.input_summary[:80]}) → {tc.result_summary[:80]}")
        if self.answer:
            lines.append(f"Answer: {self.answer[:200]}")
        return "\n".join(lines)

def record_episode(messages: list, outcome: dict) -> Episode:
    """Build an Episode from a completed agent run's message history."""
    tool_calls = []
    for msg in messages:
        if msg["role"] != "assistant":
            continue
        content = msg["content"] if isinstance(msg["content"], list) else []
        for block in content:
            btype = getattr(block, "type", block.get("type") if isinstance(block, dict) else None)
            if btype == "tool_use":
                name = getattr(block, "name", block.get("name", ""))
                inp = getattr(block, "input", block.get("input", {}))
                tool_calls.append(ToolCallRecord(
                    tool=name,
                    input_summary=str(inp)[:100],
                    result_summary="(see observations)",
                ))

    return Episode(
        goal=messages[0]["content"] if messages else "",
        outcome=outcome.get("status", "unknown"),
        answer=outcome.get("answer"),
        tool_calls=tool_calls,
        iterations_used=outcome.get("iterations", 0),
        total_input_tokens=outcome.get("total_input_tokens", 0),
    )
